backend_solution:
// e2e-099: real provider boundary for Revenue events for analytics: MRR, churn, expansion
export async function handleE2E099Webhook(req, deps) {
  const raw = Buffer.from(await req.arrayBuffer());
  const verified = deps.provider.verifySignature(raw, req.headers);
  const inserted = await deps.inbox.insertOnce({ providerEventId: verified.id, type: verified.type, raw });
  if (!inserted) return { status: 200, body: { duplicate: true } };
  await deps.queue.enqueue('revenue_events_for_analytics_mrr_c', { providerEventId: verified.id });
  return { status: 200, body: { received: true } };
}

